import{_ as t,o as a,c as o,a2 as d}from"./chunks/framework.BYlK8ftn.js";const p=JSON.parse('{"title":"Minimap HUD (radar)","description":"","frontmatter":{},"headers":[],"relativePath":"guide/minimap.md","filePath":"guide/minimap.md","lastUpdated":1782034383000}'),r={name:"guide/minimap.md"};function n(i,e,s,c,h,l){return a(),o("div",null,[...e[0]||(e[0]=[d('<h1 id="minimap-hud-radar" tabindex="-1">Minimap HUD (radar) <a class="header-anchor" href="#minimap-hud-radar" aria-label="Permalink to &quot;Minimap HUD (radar)&quot;">​</a></h1><p>The minimap is a small top-down <strong>radar</strong> pinned to the bottom-centre of the HUD during live play. It answers two questions at a glance: <em>where am I</em> and <em>where are the caravans I&#39;m meant to raid</em> — plus <em>where is the danger</em>.</p><p>It is part of the <strong>Карта минитюра</strong> feature (FLO-446) and ships as a clean, legible default; visual styling may be refined in a follow-up.</p><h2 id="what-it-shows" tabindex="-1">What it shows <a class="header-anchor" href="#what-it-shows" aria-label="Permalink to &quot;What it shows&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Marker</th><th>Colour</th><th>Meaning</th></tr></thead><tbody><tr><td>Square frame</td><td>white (faint)</td><td>The 600×600 world play area (<code>WORLD_SIZE</code>, <code>src/scenes/worldBounds.ts</code>).</td></tr><tr><td>Dot + line</td><td>cyan</td><td>The player. The line is the facing indicator (capsule <code>rotationY</code>).</td></tr><tr><td>Dots</td><td>gold</td><td>Living <strong>caravans</strong> — the raid objective (цель).</td></tr><tr><td>Dots</td><td>red</td><td>Living <strong>soldiers + archers</strong> — threats.</td></tr><tr><td>Label</td><td>—</td><td><code>Caravans &lt;raided&gt;/&lt;target&gt;</code> objective counter (from Redux <code>game</code> slice).</td></tr></tbody></table><p>Dead enemies and raided caravans drop off the radar, so the gold dots are always the <em>remaining</em> objectives.</p><h2 id="where-the-positions-come-from" tabindex="-1">Where the positions come from <a class="header-anchor" href="#where-the-positions-come-from" aria-label="Permalink to &quot;Where the positions come from&quot;">​</a></h2><p>Player and enemy world positions live <strong>only in the Babylon scene</strong>, never in Redux — streaming them through React/Redux every frame would blow the 60 fps re-render budget (see <a href="./performance-budget">performance-budget.md</a>). Instead:</p><ol><li>The active zone scene (<code>forestScene.ts</code>, <code>humanLandsScene.ts</code>) builds a <code>MinimapSnapshot</code> from the fixed-step loop, <strong>throttled to ~10 Hz</strong> (not every frame), and fires it through the <code>onMinimapTick</code> zone-scene option. The player pose is read via the existing <code>readPlayerTransform()</code> bridge; caravans and threats are read from the scene&#39;s live enemy arrays.</li><li><code>GameCanvas</code> stashes the latest snapshot on the render-free bridge in <code>src/game/minimap/</code> (<code>publishMinimapSnapshot</code>) — <strong>no Redux dispatch, no React <code>setState</code></strong>. It clears the snapshot on scene teardown.</li><li>The <code>&lt;Minimap&gt;</code> component owns its own <code>&lt;canvas&gt;</code> and a <code>requestAnimationFrame</code> loop that reads the latest snapshot (<code>readMinimapSnapshot</code>) and paints it imperatively. World coordinates <code>[-300, +300]</code> map to canvas pixels via the pure, unit-tested <code>worldToMinimap()</code> (world +X → right, +Z → up).</li></ol><p>The canvas is <code>pointer-events: none</code>, so it never intercepts clicks meant for the world, and it renders nothing outside the <code>playing</code> phase (hidden in the menu and while paused).</p><h2 id="files" tabindex="-1">Files <a class="header-anchor" href="#files" aria-label="Permalink to &quot;Files&quot;">​</a></h2><ul><li><code>src/game/minimap/index.ts</code> — snapshot types, the <code>worldToMinimap</code> projection, and the publish/read bridge.</li><li><code>src/app/Minimap.tsx</code> — the canvas component + draw loop.</li><li><code>src/scenes/zoneScenes.ts</code> / <code>forestScene.ts</code> / <code>humanLandsScene.ts</code> / <code>mountainsScene.ts</code> — the throttled <code>onMinimapTick</code> emitter.</li><li><code>src/scenes/GameCanvas.tsx</code> — wires the callback to the bridge.</li><li><code>src/styles/global.css</code> — <code>.hud-minimap*</code> styles.</li></ul>',12)])])}const u=t(r,[["render",n]]);export{p as __pageData,u as default};
